import React, { useState } from "react";

function IndividualAnalysis({ 
  customerData, 
  onInputChange, 
  onAnalyze, 
  onReset,
  loading, 
  results 
}) {
  const [activeTab, setActiveTab] = useState("core");

  const handleChange = (e) => {
    const { name, value, type } = e.target;
    const processedValue = type === "number" ? parseFloat(value) || 0 : value;
    onInputChange({ ...customerData, [name]: processedValue });
  };

  const renderField = (label, name, type = "number", options = null, step = "any") => (
    <div className="field">
      <label htmlFor={name}>{label}</label>
      {options ? (
        <select 
          id={name}
          name={name} 
          value={customerData[name]} 
          onChange={handleChange}
          className="form-select"
        >
          {options.map((opt, i) => (
            <option key={i} value={opt}>
              {opt}
            </option>
          ))}
        </select>
      ) : (
        <input 
          id={name}
          type={type} 
          name={name} 
          value={customerData[name]} 
          onChange={handleChange}
          step={step}
          min={type === "number" ? "0" : undefined}
          className="form-input"
        />
      )}
    </div>
  );

  const renderResults = () => {
    if (!results) return null;

    const probability = results.probability !== undefined ? results.probability : 
                       results.churn_probability !== undefined ? results.churn_probability : 0;
    const prediction = results.prediction !== undefined ? results.prediction : 
                      results.churn_prediction !== undefined ? results.churn_prediction : false;

    return (
      <div className="results-card">
        <h3>📊 Prediction Results</h3>
        <div className="results-content">
          <div className="prediction-result">
            <div className={`churn-indicator ${prediction ? 'high-risk' : 'low-risk'}`}>
              <span className="indicator-dot"></span>
              {prediction ? 'High Churn Risk' : 'Low Churn Risk'}
            </div>
          </div>
          
          <div className="probability-meter">
            <label>Churn Probability</label>
            <div className="meter-container">
              <div 
                className="meter-fill" 
                style={{ width: `${(probability * 100).toFixed(1)}%` }}
              ></div>
              <span className="meter-text">
                {(probability * 100).toFixed(1)}%
              </span>
            </div>
          </div>

          {results.feature_importance && (
            <div className="feature-importance">
              <h4>Key Influencing Factors</h4>
              <div className="factors-list">
                {Object.entries(results.feature_importance)
                  .slice(0, 5)
                  .map(([feature, importance]) => (
                  <div key={feature} className="factor-item">
                    <span className="factor-name">{feature.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}</span>
                    <span className="factor-value">{(importance * 100).toFixed(1)}%</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          <details className="raw-data">
            <summary>View Raw Data</summary>
            <pre>{JSON.stringify(results, null, 2)}</pre>
          </details>
        </div>
      </div>
    );
  };

  return (
    <div className="tabbed-layout">
      <div className="tabs">
        <button
          className={`tab-btn ${activeTab === "core" ? "active" : ""}`}
          onClick={() => setActiveTab("core")}
        >
          💰 Core Metrics
        </button>
        <button
          className={`tab-btn ${activeTab === "logistics" ? "active" : ""}`}
          onClick={() => setActiveTab("logistics")}
        >
          🛠️ Service & Logistics
        </button>
        <button
          className={`tab-btn ${activeTab === "demographics" ? "active" : ""}`}
          onClick={() => setActiveTab("demographics")}
        >
          👤 Demographics
        </button>
      </div>

      <div className="tab-content fade-in">
        {activeTab === "core" && (
          <div className="section-card">
            <h2>💰 Core Metrics</h2>
            <div className="grid">
              {renderField("Tenure (months)", "Tenure", "number", null, "0.1")}
              {renderField("Order Count", "OrderCount", "number", null, "1")}
              {renderField("Cashback Amount (₹)", "CashbackAmount", "number", null, "100")}
              {renderField("Order Hike %", "OrderAmountHikeFromlastYear", "number", null, "0.1")}
              {renderField("Coupons Used", "CouponUsed", "number", null, "1")}
              {renderField("Devices Registered", "NumberOfDeviceRegistered", "number", null, "1")}
              {renderField("Satisfaction Score (1-5)", "SatisfactionScore", "number", null, "1")}
            </div>
          </div>
        )}

        {activeTab === "logistics" && (
          <div className="section-card">
            <h2>🛠️ Service & Logistics</h2>
            <div className="grid">
              {renderField("Days Since Last Order", "DaySinceLastOrder", "number", null, "1")}
              {renderField("Hours On App", "HourSpendOnApp", "number", null, "0.1")}
              {renderField("Warehouse Distance (km)", "WarehouseToHome", "number", null, "1")}
              {renderField("Number of Addresses", "NumberOfAddress", "number", null, "1")}
              {renderField("Complaint Filed", "Complain", "select", [0, 1])}
              {renderField("Preferred Login Device", "PreferredLoginDevice", "select", [
                "Mobile Phone",
                "Computer",
                "Phone",
                "Tablet",
              ])}
              {renderField("Preferred Order Category", "PreferedOrderCat", "select", [
                "Laptop & Accessory",
                "Mobile & Accessory",
                "Grocery",
                "Fashion",
                "Electronics",
                "Others",
              ])}
            </div>
          </div>
        )}

        {activeTab === "demographics" && (
          <div className="section-card">
            <h2>👤 Demographics</h2>
            <div className="grid">
              {renderField("Gender", "Gender", "select", ["Male", "Female", "Other"])}
              {renderField("Marital Status", "MaritalStatus", "select", ["Married", "Single", "Divorced"])}
              {renderField("City Tier", "CityTier", "select", [1, 2, 3])}
              {renderField("Preferred Payment Mode", "PreferredPaymentMode", "select", [
                "Credit Card",
                "Debit Card",
                "UPI",
                "Net Banking",
                "Cash on Delivery",
                "E-Wallet",
              ])}
            </div>
          </div>
        )}
      </div>

      <div className="action-buttons">
        <button 
          className="secondary-btn" 
          onClick={onReset}
          disabled={loading}
        >
          🔄 Reset Form
        </button>
        <button 
          className="analyze-btn" 
          onClick={onAnalyze} 
          disabled={loading}
        >
          {loading ? (
            <>
              <div className="spinner"></div>
              Analyzing...
            </>
          ) : (
            "🚀 Run Prediction"
          )}
        </button>
      </div>

      {renderResults()}
    </div>
  );
}

export default IndividualAnalysis;
